contents.script:
Double regCap       = context.getDouble(@C_F_REGCAP);
Double paidCapRatio = context.getDouble(@C_F_PAIDCAPRATIO);
String estabDateStr = context.getString(@C_D_ESTABDATE);  // ← 改用 getString

if (regCap == null || paidCapRatio == null) { return false; }
if (estabDateStr == null || estabDateStr.trim().isEmpty()) { return false; }
if (regCap < 50000000.0) { return false; }
if (paidCapRatio >= 0.05) { return false; }

// 截取 yyyy-MM-dd 部分（兼容含时间戳格式 "2021-06-12 16:16:19"）
String datePart = estabDateStr.trim().substring(0, 10);
Date estabDate = new java.text.SimpleDateFormat("yyyy-MM-dd").parse(datePart);
if (estabDate == null) { return false; }

// 用 Calendar 计算精确3年前（正确处理闰年）
Calendar cal = Calendar.getInstance();
cal.add(Calendar.YEAR, -3);
if (estabDate.after(cal.getTime())) { return false; }

return true;

